SELECT sales_count
FROM size_analysis
WHERE size_id = 0 AND report_date = '2023-09-01';

SELECT SUM(sales_count) AS total_sales
FROM size_analysis
WHERE report_date = '2023-09-01';

SELECT product_id, rating
FROM products_reviews
WHERE review_id = 0;

SELECT COUNT(*) AS review_count
FROM products_reviews
WHERE product_id = 0;

SELECT product_id, COUNT(review_id) AS total_reviews
FROM products_reviews
GROUP BY product_id;
